export const pclActivities: Activity[] = [
  {"id":"pcl-beaded-friendship-rings","title":"Beaded Pipe-Cleaner Rings & Bracelets","altNames":["pony bead rings","pipe cleaner jewelry","beaded wire bracelets","twist rings"],"type":"Craft","place":"Both","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Thread pony beads onto a pipe cleaner and twist it into a ring or bracelet that actually fits and stays on.","materials":["Pipe cleaners, 1-2 per camper","Pony beads, a generous cupful per table","Scissors, 1 per table","Optional: small bowls to sort beads by color"],"materialTags":["Pipe cleaners","Pony beads","Scissors"],"steps":["Give each camper a pipe cleaner and have them wrap it once around a finger (for a ring) or two-to-three fingers held together (for a bracelet) to find the right size.","Slide pony beads onto the pipe cleaner, leaving about an inch bare at each end.","Bend the beaded section into a circle so the two bare ends meet.","Twist the two bare ends together two or three times to lock the loop closed.","Tuck the twisted tail flat against the beads or trim it with scissors so nothing pokes the skin.","Slide it on and adjust the circle until it sits comfortably."],"notes":"Sort beads into color bowls before camp so the table doesn't turn into a bead avalanche. Younger campers do best with bigger beads and a counselor doing the final twist; older campers can attempt color patterns or spell initials with letter-style beads. To scale up for g79, challenge them to design a repeating 3- or 4-color pattern or make a matching set for a friend.","safety":"Trimmed pipe-cleaner ends have a sharp wire tip — always fold or tuck the cut end inward and do a quick 'poke check' on every finished piece before campers wear it.","ages":["g13","g46","g79"],"rating":4,"links":[{"label":"The Beadery & friendship bracelets (CampMinder)","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"}],"variations":["Make a stretchy-fit bracelet by twisting two pipe cleaners end-to-end for a bigger wrist.","Spell your name or a short word using letter beads spaced between color beads.","For g79, design a symmetrical mirror pattern that reads the same from both ends, then make a matched pair to trade.","Younger campers can make a simple 'mood ring' with just three beads and a counselor-finished twist."],"subsets":[["Hold the pipe cleaner snug but not tight around the finger or fingers.","Pinch the spot where it overlaps to mark the size."],["Keep beads away from the very ends so there's room to twist."],[],["Twist firmly so it won't pop open, but don't over-twist or the wire weakens."],["Run a fingertip over the join to confirm no wire is sticking out."],[]]},
  {"id":"pcl-bent-wire-bugs","title":"Bent-Wire Bugs & Beetles","altNames":["pipe cleaner insects","wire bugs","fuzzy beetles","pony bead bugs"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Twist pipe cleaners and pony beads into six-legged bugs with bendable antennae that can grip a pencil or perch on a backpack.","materials":["Pipe cleaners, 2-3 per camper","Pony beads for the body, 4-6 per camper","Markers","Scissors","Optional: small paper for a 'field guide' label"],"materialTags":["Pipe cleaners","Pony beads","Markers","Scissors"],"steps":["Thread 4-6 pony beads onto one pipe cleaner to form the bug's body, then twist the two ends together to close the body into a teardrop.","Take a second pipe cleaner and lay it across the middle of the body, then twist it once underneath so it sticks out as two legs.","Repeat with more short pipe-cleaner pieces until the bug has six legs (three per side), then bend each leg into a little foot.","Make antennae by twisting a short bent piece onto the head end and curling the tips.","Bend the legs so the bug actually stands, or curl them so it can grip a pencil or a backpack strap.","Add eyes with a marker dot on the front bead and name your species on a paper label."],"notes":"This is a great 'free-build' craft — show one example, then let campers invent their own species. Counselors should pre-cut a few pipe cleaners in half so leg pieces are ready. To push g79 harder, require anatomical accuracy (insects have exactly six legs and three body segments) and have them build a beetle, an ant, and a bee that are clearly different.","safety":"Bending legs repeatedly can snap the wire and leave a sharp burr — show campers to bend gently and tuck or trim any exposed wire ends so the bug is safe to handle and clip onto a bag.","ages":["g46","g79"],"rating":4,"media":[{"title":"How to make a ladybug bug out of pipe cleaners step by step - DIY craft video","url":"https://www.youtube.com/watch?v=E7ZkbdHl6sw"}],"links":[{"label":"STEM & nature crafts (Little Bins for Little Hands)","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a 'pollinator' bee with yellow and black beads and tissue-paper wings taped to the body.","Build a spider instead with eight legs and a pony-bead body — tie into the spider-web craft.","For g79, build a scientifically correct insect with three body segments and six legs, then write a two-line field-guide entry for its habitat.","Turn finished bugs into pencil-toppers by curling the legs tightly around a pencil."],"subsets":[["Push beads to the center before twisting so the body stays plump."],["Center the leg piece so both sides come out even."],["Space the three pairs of legs along the body, not bunched at one end.","Bend the very tip of each leg into a tiny foot for standing."],[],[],[]]},
  {"id":"pcl-flowers-bouquet","title":"Pipe-Cleaner Flowers & Bouquet","altNames":["wire flowers","pipe cleaner roses","fuzzy bouquet","twist flowers"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Loop and twist pipe cleaners into petals and leaves to build a flower with a sturdy stem, then bundle the whole table's flowers into a bouquet.","materials":["Pipe cleaners, 3-4 per flower in petal and stem colors","Pony beads for flower centers, 1 per flower","Scissors","Optional: paper cup as a vase","Optional: green paper for leaves"],"materialTags":["Pipe cleaners","Pony beads","Scissors","Paper cups"],"steps":["Make a petal by bending a pipe cleaner into a loop and twisting the base so the loop stays closed.","Make four or five more loops the same size and gather all their twisted bases together in a bunch.","Slide a pony bead onto a separate 'stem' pipe cleaner and push it to the center of the petals to be the flower's middle.","Wrap the stem pipe cleaner tightly around all the petal bases to bind them into a flower head.","Fan out the petal loops evenly so the flower opens up into a circle.","Add a leaf by twisting a small folded pipe cleaner partway down the stem, then stand the flower in a paper-cup vase."],"notes":"Demo one full flower slowly before turning campers loose; the binding-the-petals step is where most get stuck, so float around for it. Let campers make two or three flowers and pool them into a shared table bouquet — it makes a great gift for the camp office. For g79, set a higher bar: a multi-layer rose made by coiling a single long pipe cleaner into a spiral, which takes real patience and dexterity.","safety":"The stem pipe cleaner gets twisted tightly and can leave a wire end at the wrap point — have campers fold that end down flat against the stem so the bouquet is safe to hold and hand off.","ages":["g46","g79"],"rating":4,"media":[{"title":"How to make easy pipe cleaner flowers - step-by-step beginner video tutorial","url":"https://www.youtube.com/watch?v=J7SDJFLZjNw"}],"links":[{"label":"Classic summer camp crafts (Our Days Outside)","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make a tulip with three tall straight petals pinched at the tips instead of loops.","Add beads along the stem for a beaded-stem flower.","For g79, build a coiled spiral rose from one long pipe cleaner and add a second pipe cleaner wrapped as a thorny stem.","Make a whole field of small flowers and chalk a garden border to 'plant' them in outside."],"subsets":[["Keep all petal loops the same size by looping around two fingers each time."],["Twist each base the same number of turns so they bundle neatly."],[],["Wrap at least three full times so the flower head can't slip apart."],["Gently pull each loop outward and shape it into a rounded petal."],[]]},
  {"id":"pcl-mini-sculptures","title":"Free-Form Mini Wire Sculptures","altNames":["pipe cleaner sculpture","wire art","abstract twist sculpture","fuzzy figures"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Use pipe cleaners as bendable wire to sculpt a standing mini figure, animal, or abstract piece on a cardboard base.","materials":["Pipe cleaners, 4-8 per camper in mixed colors","Cardboard squares for a base, 1 per camper (about 10cm)","Pony beads for accents","Scissors","Markers"],"materialTags":["Pipe cleaners","Cardboard","Pony beads","Scissors","Markers"],"steps":["Pick a subject — a dancer, an animal, a tree, or a totally abstract shape — and sketch the basic pose in the air with one pipe cleaner.","Build a frame: twist two or three pipe cleaners together for a strong core, then branch out limbs, legs, or arms.","Stand the sculpture up by poking the base ends through a cardboard square and bending them flat underneath like tent stakes.","Add detail and bulk by wrapping more pipe cleaners around the frame, coiling them for texture.","Thread on pony beads or curl wire spirals for accents like hands, leaves, or eyes.","Title your piece and write it on the cardboard base with a marker."],"notes":"Frame this as 'sculpture, not a kit' — there's no single right answer, which makes it a strong rainy-spell or quiet-block activity. Keep a couple of finished examples around (a tree, a figure, an abstract) so campers see the range. To stretch g1012, set a constraint like 'must balance on one point' or 'tell a story with two figures interacting,' which turns it into a real design problem.","safety":"Twisting many pipe cleaners together creates stiff bundles with wire ends that can scratch — keep cut ends folded into the sculpture and remind campers not to wave the pointed frame near faces.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"How To: Pipe Cleaner People — Art Projects For Kids (build a standing figure) — video tutorial","url":"https://www.youtube.com/watch?v=zVkDp9sIjsU"}],"links":[{"label":"STEM & art camp activities (Little Bins for Little Hands)","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a Calder-style mobile by hanging small wire shapes from a pipe-cleaner arc balanced on string.","Do a 'one continuous line' sculpture using a single long pipe cleaner with no cuts.","For g1012, sculpt a figure mid-action that balances on one point of contact with the base — a real engineering challenge.","Make a themed table set (an underwater scene, a forest) where each camper's piece is one part of a shared diorama."],"subsets":[["Decide whether your piece stands tall, sits wide, or hangs."],["Twisting a core first keeps the sculpture from flopping over."],["Push the ends through the cardboard then splay them like an X underneath for a firm footing."],["Coil a pipe cleaner around a pencil first to make ready-made springs and curls."],[],[]]},
  {"id":"pcl-finger-puppets","title":"Pipe-Cleaner Finger Puppets","altNames":["finger creatures","wire puppets","ring puppets","pipe cleaner critters"],"type":"Craft","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Twist a pipe-cleaner ring that hugs your finger and build a tiny puppet on top, then put on a two-minute show.","materials":["Pipe cleaners, 2-3 per camper","Pony beads for eyes","Markers","Scissors","Small scraps of paper for ears, wings, or hair","Glue"],"materialTags":["Pipe cleaners","Pony beads","Markers","Scissors","Paper","Glue"],"steps":["Wrap one pipe cleaner around your finger twice and twist the ends to make a snug ring that won't fall off.","Twist a second pipe cleaner onto the ring and shape it into a head, body, or wings for your character.","Add a face by sliding on pony-bead eyes or drawing them on with marker.","Cut tiny ears, a tail, or hair from paper scraps and glue or twist them on.","Slip the puppet onto your finger and make sure it stays put and can 'wave.'","Pair up and put on a 60-second puppet conversation between your two characters."],"notes":"This skews younger and energetic — the puppet show at the end is the payoff, so leave five minutes for it. Counselors can pre-curl a few finger rings for campers who struggle with the twist. To make it work for the top of the g46 band, add a storytelling layer: each pair gets a prompt card and has to improvise a scene with a beginning, problem, and ending.","safety":"The finger ring can be twisted too tight and pinch — check that each camper can slide their puppet on and off easily, and tuck the ring's twisted end away from the skin.","ages":["g13","g46"],"rating":3,"media":[{"title":"Kids Activity – How to Make Pipe Cleaner Finger Puppets | Kindermusik — video tutorial","url":"https://www.youtube.com/watch?v=1gu07kJZczI"}],"links":[{"label":"Camp theme & character crafts (S&S Blog)","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Make a whole hand of five puppets that act out a story together.","Build under-the-sea puppets (octopus, fish, crab) to tie into an ocean theme.","For older g46 campers, give story-prompt cards and require an improvised scene with a clear beginning, middle, and end.","Make 'monster' puppets with mismatched googly-drawn eyes and wild paper hair."],"subsets":[["Two wraps gives a ring that grips without pinching.","Test it on your finger before twisting it shut."],[],[],["A dab of glue holds paper parts; let it set a minute before playing."],[],["Trade who talks first so both puppets get a line."]]},
  {"id":"pcl-fidget-gadgets","title":"Pipe-Cleaner Fidget Gadgets","altNames":["fidget toys","bead slider fidget","pipe cleaner spinner","calm-down gadget"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Design a pocket-sized fidget — a bead slider, a coil twirler, or a clicky loop — engineered to be quietly satisfying.","materials":["Pipe cleaners, 2-4 per camper","Pony beads, a handful per camper","Scissors","A pencil for coiling","Optional: rubber bands"],"materialTags":["Pipe cleaners","Pony beads","Scissors","Rubber bands"],"steps":["Choose a fidget action you want: beads that slide, a coil that springs, or a loop that flips.","For a bead slider, thread several pony beads onto a pipe cleaner and bend both ends into closed loops so beads can shuttle back and forth but never fall off.","For a spring twirler, wrap a pipe cleaner tightly around a pencil, slide it off, and add a bead on each end as a handle.","Test your gadget and tweak it — add or remove beads, tighten the coil — until the motion feels smooth and quiet.","Connect two pieces with a twist or rubber band if you want a combined gadget.","Trade gadgets with a neighbor and rate how satisfying each one is to use."],"notes":"This is secretly an engineering iteration exercise dressed up as a fidget craft — the 'test and tweak' step is the whole point, so encourage redesign rather than one-and-done. Works well as a calm-down or transition activity. For g1012, frame it as a design brief: it must be silent, one-handed, and pocket-sized, and they have to explain why their design meets all three.","safety":"Closed end-loops are mandatory on bead sliders so beads can't come off and become a choking or slip hazard — check every slider has both ends sealed before campers pocket them.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"How to create a Fidget toy from beads and a pipe cleaner — video tutorial","url":"https://www.youtube.com/watch?v=goQOC4TS-NE"}],"links":[{"label":"Maker & invention challenges (Little Bins for Little Hands)","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a 'worry coil' you can stretch and release with a satisfying springy pull.","Build a counting fidget with exactly ten beads to slide back and forth.","For g1012, run it as a design challenge — silent, one-handed, pocket-sized — and have campers pitch their gadget in one sentence.","Make a linked-loop chain fidget where several rings click against each other."],"subsets":[[],["Bend each end into a full closed loop, not just a hook, so beads stay trapped."],["Wind the coils close together for a tighter spring.","Slide it off the pencil slowly so the coils keep their shape."],["Change one thing at a time so you know what improved it."],[],["Give an honest rating and one suggestion to improve it."]]},
  {"id":"pcl-spider-webs","title":"Pipe-Cleaner Spider Webs","altNames":["wire spider web","web and spider craft","yarn web","halloween web craft"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Build a spoke-and-spiral web by weaving yarn across a pipe-cleaner frame, then add a beaded spider to guard it.","materials":["Pipe cleaners, 4-6 per camper","Yarn or string, about 1 meter per camper","Pony beads for the spider","Scissors","Optional: cardboard ring as a base"],"materialTags":["Pipe cleaners","Yarn","Pony beads","Scissors","Cardboard"],"steps":["Twist three or four pipe cleaners together at their centers so they fan out like the spokes of a wheel.","Bend the spoke tips slightly so they hold their spread-out shape.","Tie one end of the yarn to the center, then spiral the yarn outward, wrapping it once around each spoke as you go.","Keep spiraling out to the spoke tips, then tie off and trim the yarn.","Make a spider by threading pony beads onto a short pipe cleaner for the body and twisting on bent legs.","Perch the spider on the web and bend a spoke into a hook so the whole web can hang up."],"notes":"The yarn-spiral step is fiddly; demo it big and slow, and pre-cut yarn to length so it doesn't tangle. Pairs well with the bent-wire-bugs craft as a 'creepy crawly' block. To raise the bar for g79, require a true radial web with evenly spaced spirals and have them count the legs correctly (eight) on an anatomically reasonable spider.","safety":"Spoke tips are sharp wire points that splay outward at face height when the web is held up — have campers curl every spoke tip into a tiny loop before they hang or wave the web around.","ages":["g46","g79"],"rating":3,"media":[{"title":"Pipe Cleaner Crafts for a Spider Web — video tutorial","url":"https://www.youtube.com/watch?v=sBy14N_SCg8"}],"links":[{"label":"Nature & STEM crafts (Little Bins for Little Hands)","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a giant team web by twisting several campers' frames together into one big wall web.","Use glow or bright yarn and add bead 'dewdrops' along the spiral.","For g79, build a precise radial web with eight evenly spaced spokes and consistent spiral spacing, then research one real spider fact to share.","Skip the spider and weave a colorful 'God's eye' style ornament on the spokes instead."],"subsets":[["Twist the centers tightly so the spokes don't spin loose."],[],["Keep gentle tension on the yarn so the web doesn't sag.","Loop the yarn fully around each spoke so it grips."],[],["Bend the legs into a slight arch so the spider 'stands' on the web."],["Curl the hook spoke so it grabs a string or branch."]]},
  {"id":"pcl-name-word-shapes","title":"Bent-Wire Name & Word Shapes","altNames":["pipe cleaner letters","wire word art","name bender","cursive wire signs"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Bend a single pipe cleaner into your name in flowing cursive — one continuous line, no cuts — and mount it as a sign.","materials":["Pipe cleaners, 1-2 per camper","Cardboard for mounting, 1 piece per camper","Masking tape","Markers","Pony beads for accents","Scissors"],"materialTags":["Pipe cleaners","Cardboard","Masking tape","Markers","Pony beads","Scissors"],"steps":["Write your name or a short word on paper in connected cursive as a bending guide.","Starting at one end of a pipe cleaner, bend it to follow the first letter, keeping the wire as one continuous line.","Flow straight into the next letter without cutting — the connecting strokes between letters become part of the design.","If you run out of wire, twist a fresh pipe cleaner onto the end and keep going.","Lay the finished wire word on a cardboard backing and tape the back of each letter down flat.","Decorate the board around your word with markers and a few twisted-wire flourishes or beads."],"notes":"Cursive is the trick here — it lets the whole word be one connected line, which is the satisfying part. Have a printed cursive alphabet on the table for campers who don't write cursive. To challenge g1012, require a longer phrase or a 3-D free-standing word that balances on its own without a backing board, which forces real structural thinking.","safety":"Sharp wire ends appear wherever a pipe cleaner starts, ends, or joins — fold those start and finish tips back on themselves, and press the taped letters flat so no point sticks up off the board.","ages":["g46","g79","g1012"],"rating":4,"media":[{"title":"Alphabet Keychain With Pipe Cleaner — bending pipe cleaners into letters — video tutorial","url":"https://www.youtube.com/watch?v=NCTnMluHap8"}],"links":[{"label":"Classic name & sign crafts (Our Days Outside)","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make a one-word camp motto or your cabin name as a group sign.","Bend a heart, star, or symbol instead of a word for non-writers.","For g1012, build a free-standing 3-D word with a wire base so it stands up on a shelf with no backing.","Spell the word in block letters made of separate bent pieces for a chunkier sign."],"subsets":[["Connected cursive lets the whole word be one line.","Leave a little space between letters so they don't merge."],[],[],["Twist the join tight and tuck it so it disappears into a letter."],["Tape the back of curves and corners, not just the ends, so letters hold their shape."],[]]},
  {"id":"pcl-beaded-suncatchers","title":"Beaded Pipe-Cleaner Suncatchers","altNames":["window suncatcher","bead sun hanger","wire and bead ornament","rainbow catcher"],"type":"Craft","place":"Both","ageMin":9,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Thread translucent pony beads onto a pipe-cleaner ring or shape, then hang it in a window so the summer sun glows through.","materials":["Pipe cleaners, 2-3 per camper","Pony beads, ideally translucent, a cupful per table","Yarn or string for hanging","Scissors","Optional: bowls to sort beads by color"],"materialTags":["Pipe cleaners","Pony beads","Yarn","Scissors"],"steps":["Pick a shape for your suncatcher — a circle, heart, star, or sun outline.","Thread pony beads onto a pipe cleaner, packing them close together along its whole length.","Bend the beaded pipe cleaner into your chosen shape and twist the ends together to close it.","Add an inner detail if you like by twisting a second beaded pipe cleaner across the middle as rays or a cross-bar.","Tie a loop of yarn at the top for hanging.","Hang it in a sunny window or fence link and watch the light come through the beads."],"notes":"Translucent beads make the magic happen, so set those aside for this one if you have a mix. Pre-sort beads by color so campers can plan a rainbow. To extend for g79, ask for a deliberate color gradient or a symmetric geometric pattern (like a six-ray sun where every ray matches), turning bead choice into a design decision.","safety":"The closing twist leaves a wire end right where campers grip to hang it — fold that end inward, and remind campers to hang suncatchers, not throw them, since the beaded ring is heavier than it looks.","ages":["g46","g79"],"rating":4,"media":[{"title":"EPL @ Home: How to Make a Pony Bead Suncatcher — video tutorial","url":"https://www.youtube.com/watch?v=ymNtRoyduiY"}],"links":[{"label":"Under-the-sea & color crafts (S&S Blog)","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Make a sun shape with a beaded center ring and several beaded rays twisting outward.","Make small matching ornaments to string into a window garland across the cabin.","For g79, design a color gradient that fades smoothly from one hue to another around the ring, or a symmetric six-ray sun.","Spell a tiny initial in the center with a contrasting bead color."],"subsets":[[],["Pack beads tightly so no bare wire shows in the finished shape."],["Twist the ends together firmly so the shape can't pop open."],[],["Make the hanging loop big enough to slip over a hook or branch."],[]]},
  {"id":"pcl-crowns-tiaras","title":"Pipe-Cleaner Crowns & Tiaras","altNames":["wire crown","beaded tiara","camp royalty crown","headband craft"],"type":"Craft","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Twist a fitted headband from pipe cleaners, add beaded points and spirals, and crown yourself camp royalty.","materials":["Pipe cleaners, 4-6 per camper","Pony beads, a cupful per table","Scissors","Markers","Optional: paper for jewel cutouts","Glue"],"materialTags":["Pipe cleaners","Pony beads","Scissors","Markers","Paper","Glue"],"steps":["Twist two or three pipe cleaners end-to-end into one long strand, then curve it around your head to measure the headband.","Twist the band's ends together to close the loop at the size that fits your head.","Make the front points by bending short pipe cleaners into triangles or spikes and twisting them onto the band.","Thread pony beads onto the points and spirals for jewels and sparkle.","Add curls by wrapping a pipe cleaner around a marker and twisting the spring onto the band.","Try it on, adjust the fit, and tuck any loose ends so it sits comfortably."],"notes":"High-energy and a crowd favorite, especially on a spirit or theme day. Sizing the band to the head is the step counselors most need to help with — have campers measure on their own head, not eyeball it. For the older end of g46, raise the craftsmanship bar with symmetrical points and a planned color scheme so it looks designed rather than slapped together.","safety":"A head-worn band has wire ends right near the face and scalp — every join and point must be folded flat and tucked, and do a personal fit check so nothing presses or scratches when worn.","ages":["g13","g46"],"rating":3,"media":[{"title":"Easy Crown Craft with Pipe Cleaner — Play + Learn — video tutorial","url":"https://www.youtube.com/watch?v=nCCPwftNNNI"}],"links":[{"label":"Theme-day & dress-up crafts (S&S Blog)","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Make a flower crown using the pipe-cleaner flower technique instead of points.","Make superhero-style head bands with a bold front emblem for a hero theme day.","For older g46, require a symmetrical five-point crown with a matched color pattern on both sides.","Make tiny ring-sized 'crowns' as matching jewelry instead of a headband."],"subsets":[["Measure around the widest part of your head, above the ears.","Twist a couple together to get a long enough strand."],["Close it a touch loose — it should slip on, not squeeze."],["Twist points onto the front-center of the band so they show."],[],["Wrap snugly around the marker then slide the spring off carefully."],[]]},
  {"id":"pcl-geometric-shapes-stem","title":"Geometric Wire Structures (STEM)","altNames":["pipe cleaner geometry","3D shape build","wire polyhedra","platonic solids craft"],"type":"Craft","place":"Both","ageMin":12,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Use pipe cleaners as edges and pony beads as joints to build 3-D geometric solids — cubes, pyramids, and beyond — that actually stand up.","materials":["Pipe cleaners, 6-12 per camper","Pony beads as connector joints, a handful per camper","Scissors","Straws cut into segments (optional, as rigid edges)","Paper for a build plan"],"materialTags":["Pipe cleaners","Pony beads","Scissors","Straws","Paper"],"steps":["Plan your shape on paper and count how many edges and corners (vertices) it needs — a cube is 12 edges and 8 corners.","Cut pipe cleaners to equal lengths for the edges, optionally threading each through a straw segment to make it rigid.","Build one flat face first — for a cube, twist four edges into a square, joining each corner with a pony-bead joint.","Build a second identical face, then stand four upright edges between the two faces to give the shape height.","Join every upright edge to both faces at the bead corners and adjust until the whole frame is square and stands on its own.","Test its strength by pressing gently on top, and reinforce any wobbly corner with an extra twist."],"notes":"This is the explicit STEM tie-in — it's geometry and structural engineering, so it belongs with the oldest campers. Pre-cut pipe cleaners to a couple of standard edge lengths to save time (hence Medium prep). Have a cube example built so campers can see how the two-faces-plus-uprights logic works, then dare g1012 to attempt a triangular prism, a pyramid, or even a tetrahedron and explain why triangles make a frame more rigid than squares.","safety":"Rigid straw-reinforced edges end in firm wire points — cap or fold every edge end at the bead joints, and clear enough table space so the standing frames don't get knocked into faces.","ages":["g79","g1012"],"rating":5,"media":[{"title":"Making 3D shapes with pipe cleaners and coffee straws — video tutorial","url":"https://www.youtube.com/watch?v=jVLWjBORppM"}],"links":[{"label":"STEM building challenges (Little Bins for Little Hands)","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Build a pyramid (square base, four triangle sides) and compare how it stands versus the cube.","Run a load test — see whose cube holds the most weight before collapsing, then discuss why.","For g1012, build a triangular prism or tetrahedron and explain why triangulated frames resist bending better than square ones.","Connect several shapes into a larger truss or geodesic-style dome as a team build."],"subsets":[["Sketch the shape and label vertices and edges.","Count edges so you cut the right number of pieces."],["Equal-length edges keep the shape true.","A straw over the pipe cleaner stops the edge from bending."],["Use a bead at each corner so edges pivot cleanly into right angles."],["Make the second face match the first exactly."],["Square up the frame by eye and re-twist any joint that sags."],["Triangles resist squashing better than squares — note where your frame is weakest."]]},
];
